<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;
final class AssetPlanningController{
 public function index():void{Auth::requireRole('owner','administrator','office');$pdo=Database::connection();$plans=$pdo->query("SELECT p.*,CASE WHEN p.useful_life_months>0 THEN GREATEST(p.salvage_value,p.acquisition_cost-((p.acquisition_cost-p.salvage_value)*(TIMESTAMPDIFF(MONTH,p.acquisition_date,CURDATE())/p.useful_life_months))) ELSE p.acquisition_cost END current_book_value FROM asset_replacement_plans p ORDER BY p.replacement_target_date IS NULL,p.replacement_target_date")->fetchAll();View::render('portal/assets/planning',['title'=>'Asset Replacement Planning','plans'=>$plans],'portal');}
 public function store():void{Auth::requireRole('owner','administrator','office');verify_csrf();Database::connection()->prepare('INSERT INTO asset_replacement_plans(asset_type,asset_id,acquisition_cost,acquisition_date,useful_life_months,salvage_value,replacement_target_date,replacement_budget,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE acquisition_cost=VALUES(acquisition_cost),acquisition_date=VALUES(acquisition_date),useful_life_months=VALUES(useful_life_months),salvage_value=VALUES(salvage_value),replacement_target_date=VALUES(replacement_target_date),replacement_budget=VALUES(replacement_budget),notes=VALUES(notes)')->execute([$_POST['asset_type'],(int)$_POST['asset_id'],(float)$_POST['acquisition_cost'],($_POST['acquisition_date']??'')?:null,(int)$_POST['useful_life_months'],(float)($_POST['salvage_value']??0),($_POST['replacement_target_date']??'')?:null,($_POST['replacement_budget']??'')!==''?(float)$_POST['replacement_budget']:null,trim($_POST['notes']??''),Auth::id()]);flash('success','Replacement plan saved.');redirect('/portal/asset-planning');}
}
